// Bundled Ledger Crypto Asset List (CAL) descriptors for the curated
// ERC-20 tokens. Used to clear-sign ERC-20 transfers on a Ledger: we
// send PROVIDE_ERC20_TOKEN_INFORMATION (INS 0x0A) with one of these
// blobs before SIGN_TRANSACTION so the device renders
// "Send <amount> <TICKER> to 0x…" instead of rejecting with 0x6A80
// unless the user has enabled blind signing.
//
// Each blob is a Ledger-SIGNED descriptor the device verifies against
// its embedded CAL key, so the *source* of the bytes is untrusted by
// design: bundling them here (or mirroring them) carries no integrity
// risk. The worst a wrong/missing entry can do is fail the provide
// step, after which signing falls back to the blind-sign path.
//
// Provenance: extracted once from Ledger's CAL,
//   https://cdn.live.ledger.com/cryptoassets/evm/<chainId>/erc20-signatures.json
// via @ledgerhq/hw-app-eth `byContractAddressAndChainId(...).data`, for
// the tokens in EthereumTokenCatalog. Blob layout (ledgerhq/app-ethereum):
//   tickerLen(1) || ticker(ascii) || contract(20) || decimals(4 BE) ||
//   chainId(4 BE) || Ledger signature(DER)
// Regenerate / add tokens: re-run the extraction against the CDN for the
// (chainId, contract) pairs in EthereumTokenCatalog and paste the hex.
//
// Testnet tokens (Sepolia, etc.) have no CAL entry, so they are
// intentionally absent and keep the blind-sign path. Long-tail / custom
// tokens not bundled here can be added later via a configurable,
// self-hostable descriptor endpoint (default-off); integrity stays
// guaranteed on-device, so a bank can serve a static mirror.

import Foundation

enum LedgerERC20Descriptors {

    /// Resolve the Ledger-signed descriptor for `(chainId, contract)`,
    /// or nil when none is bundled (caller then falls back to blind
    /// signing). `contract` may be `0x`-prefixed and any case.
    static func descriptor(chainId: UInt64, contract: String) -> Data? {
        let key = "\(chainId):\(normalize(contract))"
        guard let hex = bundled[key] else { return nil }
        return decodeHex(hex)
    }

    private static func normalize(_ contract: String) -> String {
        let lower = contract.lowercased()
        return lower.hasPrefix("0x") ? lower : "0x" + lower
    }

    private static func decodeHex(_ hex: String) -> Data? {
        guard hex.count.isMultiple(of: 2) else { return nil }
        var bytes = [UInt8]()
        bytes.reserveCapacity(hex.count / 2)
        var idx = hex.startIndex
        while idx < hex.endIndex {
            let next = hex.index(idx, offsetBy: 2)
            guard let b = UInt8(hex[idx..<next], radix: 16) else { return nil }
            bytes.append(b)
            idx = next
        }
        return Data(bytes)
    }

